if __name__ == "__main__":
    # Define a simple Ornstein-Uhlenbeck SDE as a test case:
    class OrnsteinUhlenbeckSDE(SDE):
        """d x = -a x dt + sigma dW_t, prior is Gaussian N(0, I)."""

        def __init__(self, a: float = 1.0, sigma: float = 1.0, N: int = 1000):
            super().__init__(N)
            self.a = a
            self.sigma = sigma

        @property
        def T(self) -> float:
            return 1.0

        def sde(
            self, x: jnp.ndarray, t: float
        ) -> Tuple[jnp.ndarray, jnp.ndarray]:
            drift = -self.a * x
            diffusion = self.sigma * jnp.ones_like(x)
            return drift, diffusion

        def prior_sampling(
            self, rng: jax.random.PRNGKey, shape: Sequence[int]
        ) -> jnp.ndarray:
            # Prior is Gaussian with variance sigma^2 / (2a)
            var = self.sigma**2 / (2 * self.a)
            return jax.random.normal(rng, shape) * jnp.sqrt(var)

        def prior_logp(self, z: jnp.ndarray) -> jnp.ndarray:
            # Log-density of N(0, var I)
            var = self.sigma**2 / (2 * self.a)
            dim = np.prod(z.shape[1:])
            log_norm = -0.5 * dim * jnp.log(2 * jnp.pi * var)
            return jax.vmap(lambda x: log_norm - 0.5 * jnp.sum(x**2) / var)(z)

    # Zero score function (i.e., no score correction)
    def zero_score(x: jnp.ndarray, t: float) -> jnp.ndarray:
        return jnp.zeros_like(x)

    # Sampling parameters
    batch_size = 512
    dim = 2
    shape = (batch_size, dim)
    rng = jax.random.PRNGKey(42)

    # Instantiate SDE and run sampler
    ou_sde = OrnsteinUhlenbeckSDE(a=1.0, sigma=0.5, N=500)
    samples = euler_maruyama_sampler(ou_sde, zero_score, rng, shape)

    # Print basic statistics to verify sampling
    print("Sample shape:", samples.shape)
    print("Mean per dimension:", jnp.mean(samples, axis=0))
    print("Std per dimension:", jnp.std(samples, axis=0))
